import java.util.*;
import java.util.function.*;
class Pair<A, B> {
    A first; B second;
    Pair(A a, B b) { first=a; second=b; }
}
public class App {
    static <T> Pair<List<T>, List<T>> partition(List<T> list, Predicate<T> condition) {
        List<T> matching    = new ArrayList<>();
        List<T> nonMatching = new ArrayList<>();
        for (T item : list) {
            (condition.test(item) ? matching : nonMatching).add(item);
        }
        return new Pair<>(matching, nonMatching);
    }
    public static void main(String[] args) {
        List<String> names = Arrays.asList("Aisha", "Raj", "Priya");
        Pair<List<String>, List<String>> result = partition(names, s -> s.length() > 3);
        System.out.println("Matching: " + result.first);
        System.out.println("Non-matching: " + result.second);
    }
}

