import java.util.function.*;
// Generic groupBy method

exercises.expected_solution:
import java.util.*;
import java.util.function.*;
class Employee {
    String name, dept;
    Employee(String n, String d) { name=n; dept=d; }
    public String toString() { return name; }
}
public class App {
    static <T, K> Map<K, List<T>> groupBy(List<T> list, Function<T, K> keyExtractor) {
        Map<K, List<T>> result = new LinkedHashMap<>();
        for (T item : list) {
            K key = keyExtractor.apply(item);
            result.computeIfAbsent(key, k -> new ArrayList<>()).add(item);
        }
        return result;
    }
    public static void main(String[] args) {
        List<String> names = Arrays.asList("Aisha", "Raj", "Priya");
        System.out.println("By length: " + groupBy(names, String::length));

        List<Employee> staff = Arrays.asList(
            new Employee("Aisha", "Engineering"),
            new Employee("Raj",   "Sales"),
            new Employee("Priya", "Engineering")
        );
        System.out.println("By dept: " + groupBy(staff, e -> e.dept));
    }
}

import java.util.function.*;
class Container<T> {
    private final T value;
    Container(T v) { value = v; }
    T get() { return value; }
    <R> Container<R> map(Function<T, R> fn) {
        return new Container<>(fn.apply(value));
    }
    public String toString() { return "Container(" + value + ")"; }
}
public class App {
    public static void main(String[] args) {
        Container<String> c = new Container<>("hello");
        System.out.println(c);

        Container<Integer> c2 = c.map(String::length);
        System.out.println(c2);

        Container<String> c3 = c2.map(n -> n + " CHARS").map(String::toUpperCase);
        System.out.println(c3);
    }
}

