import java.util.*;
import java.util.function.*;
class Employee {
    String name; double salary;
    Employee(String n, double s) { name=n; salary=s; }
    public String toString() { return name; }
}
class ListUtils {
    static <T> T firstOrDefault(List<T> list, T def) {
        return list.isEmpty() ? def : list.get(0);
    }
    static <T> T lastOrDefault(List<T> list, T def) {
        return list.isEmpty() ? def : list.get(list.size()-1);
    }
    static <T, R> List<R> map(List<T> list, Function<T, R> fn) {
        List<R> r = new ArrayList<>(list.size());
        for (T item : list) r.add(fn.apply(item));
        return r;
    }
    static <T> List<T> filter(List<T> list, Predicate<T> p) {
        List<T> r = new ArrayList<>();
        for (T item : list) if (p.test(item)) r.add(item);
        return r;
    }
    static <T> Optional<T> findFirst(List<T> list, Predicate<T> p) {
        for (T item : list) if (p.test(item)) return Optional.of(item);
        return Optional.empty();
    }
    static <T> List<T> take(List<T> list, int n) {
        return new ArrayList<>(list.subList(0, Math.min(n, list.size())));
    }
    static <T> List<T> drop(List<T> list, int n) {
        return new ArrayList<>(list.subList(Math.min(n, list.size()), list.size()));
    }
}
public class App {
    public static void main(String[] args) {
        List<Employee> staff = Arrays.asList(
            new Employee("Aisha",  95000),
            new Employee("Raj",    72000),
            new Employee("Priya",  88000),
            new Employee("Vikram", 65000),
            new Employee("Anita",  78000)
        );
        System.out.println("First: " + ListUtils.firstOrDefault(staff, null) +
                           " | Last: " + ListUtils.lastOrDefault(staff, null));
        System.out.println("Mapped names: " + ListUtils.map(staff, e -> e.name));
        System.out.println("Filtered salary>80000: " + ListUtils.filter(staff, e -> e.salary > 80000));
        System.out.println("FindFirst salary>90000: " + ListUtils.findFirst(staff, e -> e.salary > 90000));
        System.out.println("Take 3: " + ListUtils.take(staff, 3));
        System.out.println("Drop 3: " + ListUtils.drop(staff, 3));
    }
}
